const fs = require('node:fs');
const path = require('node:path');

const esbuild = require('esbuild');

const root = path.resolve(__dirname, '..');
const entryPoint = path.join(root, 'src/api/dashboard-client/entry.ts');
const outputFile = path.join(root, 'src/api/dashboard-assets/generated-client.ts');

const banner = [
  '// Generated by scripts/build-dashboard-client.js.',
  '// Source of truth: src/api/dashboard-client/entry.ts and its imports.',
  '// Do not edit this file by hand.',
  ''
].join('\n');

const result = esbuild.buildSync({
  entryPoints: [entryPoint],
  bundle: true,
  format: 'iife',
  platform: 'browser',
  target: 'es2020',
  legalComments: 'none',
  write: false
});

const bundle = result.outputFiles[0]?.text;
if (!bundle) {
  throw new Error('esbuild did not produce a dashboard client bundle');
}

const source = `${banner}export const GENERATED_DASHBOARD_CLIENT_JS = ${JSON.stringify(bundle)};\n`;
fs.writeFileSync(outputFile, source);
